static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard2dSquareInputAsymmetricKernelCustomTilingData tiling;

    const auto *x_shape = context->GetInputShape(0);
    const auto *w_shape = context->GetInputShape(1);

    // Expecting x: [N, C, H, W], weight: [K, C, R, S]
    const uint64_t n = x_shape->GetOriginShape().GetDim(0);
    const uint64_t c = x_shape->GetOriginShape().GetDim(1);
    const uint64_t h = x_shape->GetOriginShape().GetDim(2);
    const uint64_t w = x_shape->GetOriginShape().GetDim(3);

    const uint64_t k = w_shape->GetOriginShape().GetDim(0);
    const uint64_t c_w = w_shape->GetOriginShape().GetDim(1);
    const uint64_t r = w_shape->GetOriginShape().GetDim(2);
    const uint64_t s = w_shape->GetOriginShape().GetDim(3);

    // Validate simple standard conv: stride=1, pad=0, dilation=1, groups=1
    if (c != c_w) {
        return ge::GRAPH_FAILED;
    }

    const uint64_t ho = h >= r ? (h - r + 1) : 0;
    const uint64_t wo = w >= s ? (w - s + 1) : 0;

    // Parallelize over N*K tasks
    const uint64_t tasks = n * k;
    uint32_t blockDim = static_cast<uint32_t>(tasks);
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(n));
    tiling.set_c(static_cast<uint32_t>(c));
    tiling.set_h(static_cast<uint32_t>(h));
    tiling.set_w(static_cast<uint32_t>(w));
    tiling.set_k(static_cast<uint32_t>(k));
    tiling.set_r(static_cast<uint32_t>(r));
    tiling.set_s(static_cast<uint32_t>(s));
    tiling.set_ho(static_cast<uint32_t>(ho));
    tiling.set_wo(static_cast<uint32_t>(wo));
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaceSizes = context->GetWorkspaceSizes(1);
    workspaceSizes[0] = 0;
    return ge::GRAPH_SUCCESS;
}
} // namespace optiling

