static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const int64_t N = x_shape->GetDim(0);
    const int64_t C = x_shape->GetDim(1);
    const int64_t H = x_shape->GetDim(2);
    const int64_t W = x_shape->GetDim(3);

    const int64_t K = w_shape->GetDim(0);
    const int64_t Cw = w_shape->GetDim(1);
    const int64_t R = w_shape->GetDim(2);
    const int64_t S = w_shape->GetDim(3);

    if (C != Cw) {
        return GRAPH_FAILED;
    }

    const int64_t Ho = (H >= R) ? (H - R + 1) : 0;
    const int64_t Wo = (W >= S) ? (W - S + 1) : 0;

    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDimNum(4);
    y_shape->SetDim(0, N);
    y_shape->SetDim(1, K);
    y_shape->SetDim(2, Ho);
    y_shape->SetDim(3, Wo);
